"""
azureocr.models
~~~~~~~~~~~~~~~

Pydantic models used to represent a vision response.
"""

from typing import List
from pydantic import BaseModel, NonNegativeInt, NonNegativeFloat


class BoundingBox(BaseModel):
    x: float
    y: float
    w: NonNegativeFloat
    h: NonNegativeFloat


class Span(BaseModel):
    offset: int
    length: NonNegativeInt


class Styles(BaseModel):
    isHandwritten: bool
    confidence: NonNegativeFloat
    spans: List[Span]


class Metadata(BaseModel):
    width: NonNegativeInt
    height: NonNegativeInt


class Word(BaseModel):
    content: str
    boundingBox: List[float]
    confidence: NonNegativeFloat
    span: Span


class Line(BaseModel):
    content: str
    boundingBox: List[float]
    spans: List[Span]


class Pages(BaseModel):
    height: NonNegativeFloat
    width: NonNegativeFloat
    angle: float
    pageNumber: NonNegativeInt
    words: List[Word]
    spans: List[Span]
    lines: List[Line]


class ReadResult(BaseModel):
    stringIndexType: str
    content: str
    pages: List[Pages]


class VisionResponse(BaseModel):
    modelVersion: str
    metadata: Metadata
    readResult: ReadResult
